    void print() const {
        std::cout << m_hours << ":"
                  << std::setw(2) << std::setfill('0') << m_minutes << ":"
                  << std::setw(2) << std::setfill('0') << m_seconds << "\n";
    }
};

int main() {
    int h{}, m{}, s{}, h2{};
    std::cin >> h >> m >> s >> h2;
    Clock c1{ h, m, s };
    Clock c2{ h2 };
    c1.print();
    c2.print();
}

