#include <iostream>
#include <string>

class Velocity {
    int m_speed;
    std::string m_dir;
public:
    Velocity(int speed, std::string dir)
        : m_speed{ speed }, m_dir{ dir }
    {}

    Velocity(int speed)
        : Velocity{ speed, "north" }
    {}

    int getSpeed() const { return m_speed; }
    const std::string& getDir() const { return m_dir; }
};

Velocity makeVelocity(int speed, std::string dir) {
    return Velocity{ speed, dir };
}

int main() {
    int s{};
    std::string d{};
    std::cin >> s >> d;
    Velocity v{ makeVelocity(s, d) };
    std::cout << "Speed: " << v.getSpeed() << " Direction: " << v.getDir() << "\n";
}
